            aOrbiterF = (aWandererI + RotL64(aCross, 60U)) + 0x6136A16543B71A58ULL;
            aOrbiterJ = (aWandererA + RotL64(aPrevious, 3U)) + 0xCCAF69E2B907A048ULL;
            aOrbiterG = ((aWandererB + RotL64(aScatter, 21U)) + 0x034C8A2DE2B87D99ULL) + aPhaseDOrbiterAssignSaltB[(((31U - aIndex) + 12U)) & S_SALT1];
            aOrbiterA = (aWandererJ + RotL64(aIngress, 27U)) + 0x9469234D160CF44AULL;
            aOrbiterE = ((aWandererF + RotL64(aScatter, 13U)) + 0x68BB6DEC5567AA17ULL) + aPhaseDOrbiterAssignSaltA[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterK = ((aWandererK + RotL64(aPrevious, 51U)) + RotL64(aCarry, 13U)) + 0xF9CACF54E434052AULL;
            aOrbiterI = ((aWandererE + RotL64(aCross, 47U)) + RotL64(aCarry, 23U)) + 0x39B4F99B8EF2AF8FULL;
            aOrbiterH = ((aWandererH + RotL64(aIngress, 56U)) + RotL64(aCarry, 37U)) + 0xC2373A7DD2955A8CULL;
            aOrbiterD = (aWandererD + RotL64(aPrevious, 39U)) + 0x8D1047DF5B76A9CBULL;
            //
            aOrbiterF = ((aOrbiterF + aOrbiterJ) + 0x03D2CF58539C4BAFULL) + aPhaseDOrbiterUpdateSaltF[((aIndex + 17U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterF) ^ 0x186AD79B91FA1F4FULL;
            aOrbiterG = RotL64((aOrbiterG * 0x178D8E6C48D2BCDFULL), 57U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0x7DCAF3B9654E4AF6ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0xE16C91064AAAA652ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x953DF10F45ED2389ULL), 3U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterG) + 0x02C71E92D4CDCFDEULL) + aPhaseDOrbiterUpdateSaltD[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0x11DE93EB54E5F0CEULL;
            aOrbiterK = RotL64((aOrbiterK * 0x22C4DBC4EC312B53ULL), 47U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterE) + 0x1644809D3E902F85ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterI) ^ 0x812E1C4E44081A27ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x743E02A05C7745D3ULL), 51U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 0xF65A31B5D3BC25E4ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterK) ^ 0xC6E169A69D8350FEULL;
            aOrbiterF = RotL64((aOrbiterF * 0x3255F7BA3595D275ULL), 35U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterA) + 0x1BB152C097DE1E34ULL) + aPhaseDOrbiterUpdateSaltB[(((31U - aIndex) + 10U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterJ) ^ 0xCDA090E5E6EAB40BULL;
            aOrbiterI = RotL64((aOrbiterI * 0x15A272CA3C8B835BULL), 11U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterK) + 0xD8177C62542C63DFULL) + aPhaseDOrbiterUpdateSaltA[((aIndex + 11U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterH) ^ 0xD8152E2C6129476DULL;
            aOrbiterA = RotL64((aOrbiterA * 0xEED454A470C32469ULL), 19U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterI) + 0x155D1D4117ABC84EULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 0xC66EA40674CAF564ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xDE35027DB097D36DULL), 43U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterH) + 0xFC749A15F9040F08ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterD) ^ 0xF997DB0FDF01CE2DULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xC6321E51E67AD58DULL), 29U);
            //
            aIngress = RotL64(aOrbiterK, 57U) ^ aOrbiterE;
            aIngress = aIngress + (RotL64(aOrbiterH, 43U) ^ aOrbiterA);
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterD, 60U));
            aIngress = aIngress + (RotL64(aOrbiterJ, 5U) ^ aOrbiterG);
