            //
            aWandererH = aWandererH + ((RotL64(aScatter, 43U) + RotL64(aOrbiterJ, 21U)) + aOrbiterF);
            aWandererK = aWandererK ^ ((RotL64(aIngress, 24U) + RotL64(aOrbiterH, 12U)) + aOrbiterD);
