            aWandererB = aWandererB + ((RotL64(aScatter, 35U) + RotL64(aOrbiterG, 47U)) + aOrbiterI);
            aWandererJ = aWandererJ ^ (((RotL64(aCross, 3U) + RotL64(aOrbiterK, 41U)) + aOrbiterD) + aPhaseDWandererUpdateSaltA[((aIndex + 5U)) & S_SALT1]);
