            //
            aScatter = (RotL64(aIngress, 43U) ^ RotL64(aCarry, 29U)) + (RotL64(aPrevious, 57U) ^ RotL64(aCross, 14U));
            aScatter = TwistMix64::DiffuseB(aScatter);
            //
            aOrbiterE = ((aWandererH + RotL64(aScatter, 44U)) + RotL64(aCarry, 43U)) + 0x080B3BE3BD616068ULL;
            aOrbiterH = ((aWandererG + RotL64(aPrevious, 29U)) + RotL64(aCarry, 11U)) + 0x91CD6820659C8888ULL;
            aOrbiterG = (aWandererF + RotL64(aIngress, 23U)) + 0xA5DD4B4DF2DE421DULL;
            aOrbiterK = ((aWandererE + RotL64(aCross, 27U)) + RotL64(aCarry, 37U)) + 0x98A814818BBD38FCULL;
            aOrbiterJ = ((aWandererC + RotL64(aPrevious, 57U)) + 0xF599935D90695E20ULL) + aPhaseGOrbiterAssignSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterF = (aWandererD + RotL64(aCross, 13U)) + 0x741EC3A29AB44055ULL;
            aOrbiterD = (aWandererA + RotL64(aScatter, 47U)) + 0x16FAB381799F785DULL;
            aOrbiterA = (aWandererB + RotL64(aIngress, 53U)) + 0xEF89E7E1661BEADDULL;
