            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 0x658094F5CD23DBC1ULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterA) ^ 0x1A2FC49317A4EAFBULL) ^ aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 20U)) & S_SALT1];
