            //
            aOrbiterG = (aOrbiterG + aOrbiterD) + 0x305E13E931D38E6AULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterG) ^ 0xCEFBE08D812254E5ULL) ^ aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 18U)) & S_SALT1];
