            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 0x9638AFB52A556E9EULL;
            aOrbiterC = RotL64((aOrbiterC * 0xA72211776F3EB4B9ULL), 37U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterA) + 0xBE4279560D5FDFA3ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 0x97B417868326875EULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xE4632F7F48DAAA29ULL), 27U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterI) + 0x9CA8EDF4E9027E0DULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 0xFDF6A9D62410833EULL;
            aOrbiterG = RotL64((aOrbiterG * 0x55ADB9A664C52E27ULL), 13U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterE) + 0x2354066ACFC6E746ULL) + aPhaseGOrbiterUpdateSaltF[(((31U - aIndex) + 4U)) & S_SALT1];
            aOrbiterD = ((aOrbiterD ^ aOrbiterA) ^ 0x394212EEF3BD9092ULL) ^ aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x4ED7EA4BB5F42ECFULL), 53U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterH) + 0x9DAADDC45F2928F4ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterF) ^ 0xA29C79A89DAAC2C1ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x43BB5809FCC7C6EFULL), 35U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterD) + 0xBAB6F58694A36DF2ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0x855338E6F0F9C663ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x9A155D90F3446473ULL), 39U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterF) + 0xF6052D5F902FD1B7ULL) + aPhaseGOrbiterUpdateSaltB[((aIndex + 26U)) & S_SALT1];
            aOrbiterB = ((aOrbiterB ^ aOrbiterK) ^ 0x78F7EBBCFB219883ULL) ^ aPhaseGOrbiterUpdateSaltE[((aIndex + 22U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0xE0D67BA8D8EF428BULL), 47U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterG) + 0xD05AD19529098930ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterC) ^ 0xA6107197777D933CULL;
            aOrbiterE = RotL64((aOrbiterE * 0x867D0E215348A7CFULL), 21U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterK) + 0x912130A92E6918A7ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 0x635E1083BD73CD9DULL;
            aOrbiterH = RotL64((aOrbiterH * 0x38D9FC9CB1D9A835ULL), 23U);
            //
            aIngress = RotL64(aOrbiterK, 57U) ^ aOrbiterJ;
            aIngress = aIngress + (RotL64(aOrbiterG, 60U) ^ aOrbiterE);
            aIngress = aIngress + (RotL64(aOrbiterA, 23U) ^ aOrbiterD);
            aIngress = aIngress + (RotL64(aOrbiterC, 53U) ^ aOrbiterI);
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterH, 5U));
            aIngress = aIngress + RotL64(aOrbiterB, 21U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererF = aWandererF ^ ((RotL64(aScatter, 48U) + aOrbiterK) + RotL64(aOrbiterC, 37U));
            aWandererJ = aWandererJ + ((RotL64(aCross, 27U) + RotL64(aOrbiterC, 41U)) + aOrbiterI);
            aWandererI = aWandererI ^ ((RotL64(aPrevious, 3U) + RotL64(aOrbiterB, 39U)) + aOrbiterE);
            aWandererA = aWandererA + (((RotL64(aIngress, 5U) + aOrbiterG) + RotL64(aOrbiterJ, 47U)) + RotL64(aCarry, 27U));
            aWandererC = aWandererC ^ ((RotL64(aPrevious, 51U) + RotL64(aOrbiterD, 3U)) + aOrbiterA);
            aWandererB = aWandererB + ((RotL64(aCross, 53U) + aOrbiterA) + RotL64(aOrbiterE, 10U));
            aWandererG = aWandererG ^ ((RotL64(aIngress, 35U) + aOrbiterJ) + RotL64(aOrbiterC, 57U));
